def smoothclamp(x, x_min, x_max, N):
    t = np.Divide(np.Subtract(x, x_min), np.Subtract(x_max, x_min))
    t_clipped = np.Minimum(np.Maximum(t, 0.0), 1.0)
    result = 0
    for n in range(0, N + 1):
        term = np.Multiply(np.Power(np.Subtract(1.0, t_clipped), np.Subtract(N, n)), np.Power(t_clipped, n))
        coefficient = np.Multiply(np.Gcd(np.Add(n, 1), np.Add(N + 1, np.Negative(n))), np.Gcd(np.Add(n, 2), np.Add(N + 2, np.Negative(n))))
